import "dotenv/config";
import Anthropic from "@anthropic-ai/sdk";

const KEY = process.env.ANTHROPIC_API_KEY;

export const hasAnthropic = Boolean(KEY);

let _client: Anthropic | null = null;
export function client(): Anthropic {
  if (!_client) {
    if (!KEY) throw new Error("ANTHROPIC_API_KEY missing in .env");
    _client = new Anthropic({ apiKey: KEY });
  }
  return _client;
}

export const MODEL = "claude-sonnet-4-6";

export async function generateJSON<T>(opts: {
  system: string;
  user: string;
  cacheSystem?: boolean;
  maxTokens?: number;
}): Promise<T> {
  const c = client();
  const systemBlocks: Anthropic.TextBlockParam[] = [
    {
      type: "text",
      text: opts.system,
      ...(opts.cacheSystem ? { cache_control: { type: "ephemeral" } } : {}),
    },
  ];
  const res = await c.messages.create({
    model: MODEL,
    max_tokens: opts.maxTokens ?? 4096,
    system: systemBlocks,
    messages: [{ role: "user", content: opts.user }],
  });
  const text = res.content
    .filter((b): b is Anthropic.TextBlock => b.type === "text")
    .map((b) => b.text)
    .join("");
  const cleaned = text.replace(/^```json\s*/i, "").replace(/\s*```$/, "").trim();
  try {
    return JSON.parse(cleaned) as T;
  } catch (e) {
    throw new Error(`Claude returned non-JSON:\n${text.slice(0, 500)}\n\nParse error: ${(e as Error).message}`);
  }
}

