import { readFile } from "node:fs/promises";
import { join } from "node:path";
import type { Slate } from "@/lib/pipeline/types";

async function loadSlate(): Promise<Slate | null> {
  try {
    const raw = await readFile(join(process.cwd(), "data/slate/latest.json"), "utf8");
    return JSON.parse(raw) as Slate;
  } catch {
    return null;
  }
}

export const dynamic = "force-dynamic";

export default async function Home() {
  const slate = await loadSlate();

  if (!slate) {
    return (
      <main className="min-h-screen px-8 py-16 max-w-4xl mx-auto">
        <Header />
        <div className="mt-12 rounded-xl border border-neutral-200 p-8">
          <p className="text-neutral-600">
            No slate generated yet. Run <code className="px-2 py-1 bg-neutral-100 rounded font-mono">npm run slate</code> in the terminal.
          </p>
        </div>
      </main>
    );
  }

  return (
    <main className="min-h-screen px-8 py-16 max-w-4xl mx-auto">
      <Header />
      <Insight slate={slate} />
      <LongForm slate={slate} />
      <Shorts slate={slate} />
      <Pitches slate={slate} />
      <Footer slate={slate} />
    </main>
  );
}

function Header() {
  return (
    <header>
      <p className="font-mono text-xs uppercase tracking-widest text-neutral-500">Founder Channel Engine</p>
      <h1 className="mt-3 text-5xl font-semibold tracking-tight">This week&rsquo;s slate</h1>
      <p className="mt-3 text-lg text-neutral-600">
        Driven by real AI search data from Peec AI. Every artifact below traces back to a specific prompt or sub-query an AI engine actually ran.
      </p>
    </header>
  );
}

function Insight({ slate }: { slate: Slate }) {
  const i = slate.headline_insight;
