import "dotenv/config";
import { GoogleGenAI } from "@google/genai";

const KEY = process.env.GEMINI_API_KEY;

export const hasLLM = Boolean(KEY);

let _client: GoogleGenAI | null = null;
function client(): GoogleGenAI {
  if (!_client) {
    if (!KEY) throw new Error("GEMINI_API_KEY missing in .env");
    _client = new GoogleGenAI({ apiKey: KEY });
  }
  return _client;
}

export const MODEL = "gemini-2.5-pro";

export async function generateJSON<T>(opts: {
  system: string;
  user: string;
  maxTokens?: number;
  temperature?: number;
}): Promise<T> {
  const c = client();
  const res = await c.models.generateContent({
    model: MODEL,
    contents: opts.user,
    config: {
      systemInstruction: opts.system,
      responseMimeType: "application/json",
      maxOutputTokens: opts.maxTokens ?? 8192,
      temperature: opts.temperature ?? 0.7,
    },
  });
  const text = res.text ?? "";
  if (!text) throw new Error("Gemini returned empty response");
  const cleaned = text.replace(/^```json\s*/i, "").replace(/\s*```$/, "").trim();
  try {
    return JSON.parse(cleaned) as T;
  } catch (e) {
    throw new Error(`Gemini returned non-JSON:\n${text.slice(0, 500)}\n\nParse error: ${(e as Error).message}`);
  }
}

