import { peec } from "../peec/client.js";
import { generateJSON } from "../anthropic/client.js";
import type { LongFormBrief } from "./types.js";
import type { BrandReportRow, Prompt, Topic, UrlReportRow, FanoutQuery } from "../peec/types.js";

type Args = {
  projectId: string;
  ownBrandName: string;
  topics: Topic[];
  brandReport: BrandReportRow[];
  range: { start_date: string; end_date: string };
};

export async function buildLongFormBrief(args: Args): Promise<LongFormBrief> {
  const { projectId, ownBrandName, topics, range } = args;

  const blindSpot = await pickBlindSpotTopic(projectId, topics, ownBrandName, range);
  const prompts = await peec.listPrompts(projectId, { topic_id: blindSpot.id, limit: 50 });
  const topPrompts = [...prompts].sort((a, b) => b.volume - a.volume).slice(0, 5);

  const fanoutSets = await Promise.all(
    topPrompts.map((p) =>
      peec.fanoutSearch(projectId, { ...range, prompt_id: p.id, limit: 5 }).catch(() => [] as FanoutQuery[])
    )
  );
  const subQueries = uniq(fanoutSets.flat().map((f) => f.query.text)).slice(0, 8);

  const urls = await peec.urlReport(projectId, { ...range, limit: 100 });
  const ytChannels = urls
    .filter((u) => u.url.includes("youtube.com") && u.channel_title)
    .sort((a, b) => b.retrievals - a.retrievals)
    .slice(0, 5);

  const articleAuthorities = urls
    .filter((u) => !u.url.includes("youtube.com") && u.classification !== "OTHER")
    .sort((a, b) => b.citation_rate - a.citation_rate)
    .slice(0, 5);

  return generateJSON<LongFormBrief>({
    cacheSystem: true,
    system: longFormSystem(ownBrandName),
    user: JSON.stringify({
      brand: ownBrandName,
      topic: blindSpot,
      target_prompts: topPrompts.map((p) => ({ id: p.id, text: p.messages[0]?.content })),
      ai_engine_sub_queries: subQueries,
      cited_youtube_videos: ytChannels.map((u) => ({ url: u.url, channel: u.channel_title, title: u.title })),
      cited_articles: articleAuthorities.map((u) => ({ url: u.url, title: u.title, citation_rate: u.citation_rate })),
    }, null, 2),
  }).then((brief) => ({
    ...brief,
    topic: blindSpot.name,
    topic_id: blindSpot.id,
    target_prompts: topPrompts.map((p) => ({ id: p.id, text: p.messages[0]?.content ?? "" })),
    citation_targets: ytChannels.map((u) => ({
      url: u.url,
      channel_title: u.channel_title,
      why: `${u.retrievals} retrievals, ${u.citation_count} citations in last 30d`,
    })),
  }));
}

async function pickBlindSpotTopic(
  projectId: string,
  topics: Topic[],
  ownBrandName: string,
  range: { start_date: string; end_date: string }
): Promise<Topic> {
  const scores = await Promise.all(
    topics.map(async (t) => {
      const rpt = await peec.brandReport(projectId, {
        ...range,
        limit: 20,
        filters: { topic_ids: [t.id] },
      }).catch(() => [] as BrandReportRow[]);
      const own = rpt.find((r) => r.brand.name === ownBrandName);
      const competitors = rpt.filter((r) => r.brand.name !== ownBrandName);
      const compMax = competitors.reduce((m, r) => Math.max(m, r.visibility), 0);
      const ownViz = own?.visibility ?? 0;
      const gap = compMax - ownViz;
      return { topic: t, gap, ownViz };
    })
  );
  scores.sort((a, b) => b.gap - a.gap);
  return scores[0]?.topic ?? topics[0];
}

const uniq = <T>(arr: T[]) => Array.from(new Set(arr));

function longFormSystem(brand: string): string {
  return `You are a senior YouTube strategist and channel producer for ${brand}, an underdog consumer brand competing against giants. You generate one production-ready long-form video brief.

Your output must be valid JSON matching this exact schema:
{
  "title": "string — punchy YouTube title under 70 chars, no clickbait, includes the topic naturally",
  "hook": "string — first 15 seconds of script, said to camera, hooks the viewer with a contrarian or surprising claim",
  "description": "string — 2-3 paragraph YouTube description optimized for AI engine citation. Uses keywords from the sub-queries naturally. No fluff.",
  "chapters": [
    {
      "timestamp": "0:00 / 1:30 / 3:45 etc",
      "title": "string — chapter title that mirrors how AI engines fan out the question",
      "sub_query_source": "string — the actual AI sub-query this chapter answers, copied from input",
      "talking_points": ["3-5 bullet points the host should cover in this chapter"]
    }
  ],
  "b_roll": ["string — 5-8 specific shot ideas, phone-shootable"],
  "thumbnail_concept": "string — one sentence describing the thumbnail",
  "tags": ["8-12 youtube tags"]
}

Rules:
- Each chapter title MUST be derived from one of the ai_engine_sub_queries — that is the entire point. Citation depends on it.
- 6-8 chapters total. Total runtime should feel like 8-12 minutes.
- Hook must NOT start with "In this video" or "Today we're".
- Be specific about the brand's actual products, not generic positioning.
- Output ONLY the JSON, no preamble, no code fences.`;
}

import { peec } from "../peec/client.js";
import { generateJSON } from "../anthropic/client.js";
import type { ShortScript } from "./types.js";
import type { BrandReportRow, Topic } from "../peec/types.js";

type Args = {
  projectId: string;
  ownBrandName: string;
  topics: Topic[];
  brandReport: BrandReportRow[];
  range: { start_date: string; end_date: string };
};

export async function buildShorts(args: Args): Promise<ShortScript[]> {
  const { projectId, ownBrandName, topics, brandReport, range } = args;

  const competitors = brandReport
    .filter((b) => b.brand.name !== ownBrandName && b.visibility > 0.1)
    .sort((a, b) => a.sentiment - b.sentiment)
    .slice(0, 3);

  const wedges = await Promise.all(
    competitors.map(async (c) => {
      const topicScores = await Promise.all(
        topics.map(async (t) => {
          const rpt = await peec.brandReport(projectId, {
            ...range,
            limit: 20,
            filters: { topic_ids: [t.id] },
          }).catch(() => [] as BrandReportRow[]);
          const compRow = rpt.find((r) => r.brand.id === c.brand.id);
          return { topic: t, sentiment: compRow?.sentiment ?? 100, visibility: compRow?.visibility ?? 0 };
        })
      );
      const weakest = topicScores
        .filter((s) => s.visibility > 0.05)
        .sort((a, b) => a.sentiment - b.sentiment)[0] ?? { topic: topics[0], sentiment: c.sentiment };
      return { competitor: c, weakTopic: weakest.topic.name, weakSentiment: weakest.sentiment };
    })
  );

  return generateJSON<ShortScript[]>({
    cacheSystem: true,
    system: shortsSystem(ownBrandName),
    user: JSON.stringify({
      brand: ownBrandName,
      wedges: wedges.map((w) => ({
        competitor: w.competitor.brand.name,
        competitor_visibility: w.competitor.visibility,
        competitor_sentiment: w.competitor.sentiment,
        weakest_topic_for_competitor: w.weakTopic,
        sentiment_in_that_topic: w.weakSentiment,
      })),
    }, null, 2),
  });
}

function shortsSystem(brand: string): string {
  return `You are a short-form video writer for ${brand}, an underdog consumer brand. Generate exactly 3 short-form video scripts (TikTok / Reels / Shorts), each 30-45 seconds.

Each script targets a different "wedge" — a topic where a major competitor has weak sentiment in AI search results, where ${brand} can present a contrarian, honest, fan-perspective take.

Tone: enthusiast / observer voice, not corporate. The person delivering this is a real fan or community member, not a marketer. They speak with conviction and specifics.

Output must be a JSON array of exactly 3 objects, each matching:
{
  "topic": "string — the topic this short addresses",
  "competitor_wedge": { "name": "competitor brand", "sentiment": number, "weak_topic": "the topic" },
  "hook": "string — 0-3s opening line. MUST grab attention. NEVER 'Hey guys' or 'In this video'.",
  "claim": "string — 3-20s the central claim or argument, specific to the wedge",
  "payoff": "string — 20-35s the resolution, what to do, what to feel, what to share",
  "on_screen_text": ["3-5 short text overlays that appear at key moments"],
  "hashtags": ["6-10 hashtags, mix of broad + niche"],
  "shot_list": ["3-5 specific shots, phone-only, achievable in one filming session"]
}

Output ONLY the JSON array, no preamble, no code fences.`;
}

import { peec } from "../peec/client.js";
import { generateJSON } from "../anthropic/client.js";
import type { ChannelPitch } from "./types.js";
import type { UrlReportRow } from "../peec/types.js";

type Args = {
  projectId: string;
  ownBrandName: string;
  range: { start_date: string; end_date: string };
};

type ChannelAggregate = {
  channel_title: string;
  channel_url: string;
  total_retrievals: number;
  total_citations: number;
  videos: { url: string; title: string; retrievals: number; citation_count: number }[];
};

export async function buildPitches(args: Args): Promise<ChannelPitch[]> {
  const { projectId, ownBrandName, range } = args;

  const urls = await peec.urlReport(projectId, { ...range, limit: 200 });
  const yt = urls.filter((u) => u.url.includes("youtube.com") && u.channel_title);
  const byChannel = new Map<string, ChannelAggregate>();
  for (const u of yt) {
    const key = u.channel_title!;
    const channelUrl = `https://youtube.com/@${key.replace(/\s+/g, "")}`;
    const cur = byChannel.get(key) ?? {
      channel_title: key,
      channel_url: channelUrl,
      total_retrievals: 0,
      total_citations: 0,
      videos: [],
    };
    cur.total_retrievals += u.retrievals;
    cur.total_citations += u.citation_count;
    cur.videos.push({ url: u.url, title: u.title, retrievals: u.retrievals, citation_count: u.citation_count });
    byChannel.set(key, cur);
  }
  const ranked = [...byChannel.values()]
    .sort((a, b) => b.total_retrievals + b.total_citations - (a.total_retrievals + a.total_citations))
    .slice(0, 5);

  if (ranked.length === 0) return [];

  return generateJSON<ChannelPitch[]>({
    cacheSystem: true,
    system: pitchesSystem(ownBrandName),
