import "dotenv/config";
import { GoogleGenAI } from "@google/genai";

const KEY = process.env.GEMINI_API_KEY;

export const hasLLM = Boolean(KEY);

let _client: GoogleGenAI | null = null;
function client(): GoogleGenAI {
  if (!_client) {
    if (!KEY) throw new Error("GEMINI_API_KEY missing in .env");
    _client = new GoogleGenAI({ apiKey: KEY });
  }
  return _client;
}

export const PRIMARY_MODEL = process.env.GEMINI_MODEL ?? "gemini-3.1-pro-preview";
export const FALLBACK_MODEL = process.env.GEMINI_FALLBACK_MODEL ?? "gemini-2.5-pro";

const isQuotaError = (e: unknown) => {
  const msg = (e as Error)?.message ?? String(e);
  return msg.includes("RESOURCE_EXHAUSTED") || msg.includes("429") || msg.toLowerCase().includes("quota");
};

const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms));

async function callWithBackoff(model: string, contents: string, config: Record<string, unknown>, attempts = 4): Promise<{ text: string; modelUsed: string }> {
  const c = client();
  let lastErr: unknown;
  for (let i = 0; i < attempts; i++) {
    try {
      const res = await c.models.generateContent({ model, contents, config: config as never });
      return { text: res.text ?? "", modelUsed: model };
    } catch (e) {
      lastErr = e;
      if (!isQuotaError(e)) throw e;
      const delayMs = 2000 * Math.pow(2, i) + Math.floor(Math.random() * 800);
      console.warn(`[llm] ${model} 429 (attempt ${i + 1}/${attempts}), backing off ${delayMs}ms`);
      await sleep(delayMs);
    }
  }
  throw lastErr;
}

export async function generateJSON<T>(opts: {
  system: string;
  user: string;
  maxTokens?: number;
  temperature?: number;
}): Promise<T> {
  const cfg = {
    systemInstruction: opts.system,
    responseMimeType: "application/json",
    maxOutputTokens: opts.maxTokens ?? 8192,
    temperature: opts.temperature ?? 0.7,
  };

  let result: { text: string; modelUsed: string };
  try {
    result = await callWithBackoff(PRIMARY_MODEL, opts.user, cfg, 1);
  } catch (e) {
    if (!isQuotaError(e) || PRIMARY_MODEL === FALLBACK_MODEL) throw e;
    console.warn(`[llm] ${PRIMARY_MODEL} unavailable → falling back to ${FALLBACK_MODEL}`);
    result = await callWithBackoff(FALLBACK_MODEL, opts.user, cfg, 4);
  }

  const { text, modelUsed } = result;
  if (!text) throw new Error(`Gemini (${modelUsed}) returned empty response`);
  const cleaned = text.replace(/^```json\s*/i, "").replace(/\s*```$/, "").trim();
  try {
    return JSON.parse(cleaned) as T;
  } catch (e) {
    throw new Error(
      `Gemini (${modelUsed}) returned non-JSON:\n${text.slice(0, 500)}\n\nParse error: ${(e as Error).message}`
    );
  }
}

