}

async function callWithChain(contents: string, config: Record<string, unknown>): Promise<{ text: string; modelUsed: string }> {
  let lastErr: unknown;
  for (let i = 0; i < MODEL_CHAIN.length; i++) {
    const model = MODEL_CHAIN[i];
