1	import { peec } from "../peec/client";
2	import { generateJSON } from "../llm/client";
3	import type { BrandReportRow, Topic } from "../peec/types";
4	import type { ShortScript } from "./types";
5	
6	type Args = {
7	  projectId: string;
8	  ownBrandName: string;
9	  topics: Topic[];
10	  range: { start_date: string; end_date: string };
11	};
12	
13	export async function buildLowSentimentShorts(args: Args): Promise<ShortScript[]> {
14	  const { projectId, ownBrandName, topics, range } = args;
15	
16	  if (topics.length === 0) return [];
17	
18	  const topicScores = await Promise.all(
19	    topics.map(async (t) => {
20	      const rpt = await peec.brandReport(projectId, {
21	        ...range,
22	        limit: 20,
23	        filters: { topic_ids: [t.id] },
24	      }).catch(() => [] as BrandReportRow[]);
25	      const ourRow = rpt.find((r) => r.brand.name === ownBrandName);
26	      return { topic: t.name, sentiment: ourRow?.sentiment ?? 100 };
27	    })
28	  );
29	
30	  // Take up to 4 worst topics
31	  const weakestTopics = topicScores
32	    .sort((a, b) => a.sentiment - b.sentiment)
33	    .slice(0, 4);
34	
35	  return generateJSON<ShortScript[]>({
36	    system: lowSentimentSystem(ownBrandName),
37	    user: JSON.stringify({
38	      brand: ownBrandName,
39	      weak_topics: weakestTopics,
40	    }, null, 2)
41	  });
42	}
43	
44	function lowSentimentSystem(brand: string): string {
45	  return `You are a short-form video writer for ${brand}, an underdog consumer brand.
46	I will give you a list of "weak topics" where ${brand} currently has poor sentiment in AI search results.
47	
