1	import type { Slate, WeeklyContentPlan, ContentItem } from "./types";
2	
3	/**
4	 * Smartly distributes scripts from a Slate into a 7-day calendar.
5	 * Utilizes gap analysis, Tavily fresh news, and competitor remixes
6	 * to build a prioritized, non-repeating schedule.
7	 */
8	export function generateSmartPlan(slate: Slate): WeeklyContentPlan {
9	  const items: ContentItem[] = [];
10	  const start = new Date();
11	
12	  // 1. Prepare Content Pools
13	
14	  // A. Shorts (check for Tavily news urgency)
15	  const shortItems = slate.shorts.map((s) => {
16	    const isNews = !!s.fresh_news_anchor;
17	    return {
18	      type: "SHORT" as const,
19	      title: isNews ? `News Hijack: ${s.fresh_news_anchor!.title}` : s.topic,
20	      hook: s.hook,
21	      script: isNews
22	        ? `[News Anchor: ${s.fresh_news_anchor!.snippet}]\n\n${s.hook} ${s.claim} ${s.payoff}`
23	        : `${s.hook} ${s.claim} ${s.payoff}`,
24	      metadata: {
25	        topic: s.topic,
26	        hashtags: s.hashtags,
27	        platforms: ["YOUTUBE", "TIKTOK", "INSTAGRAM"] as ("YOUTUBE" | "TIKTOK" | "INSTAGRAM" | "X")[],
28	        is_urgent: isNews,
29	        is_competitor_attack: true,
30	      },
31	    };
32	  });
33	
34	  // C. Competitor Remixes (counter-narrative content)
35	  const remixItems = (slate.remixes || []).map((r) => ({
36	    type: "REMIX" as const,
37	    title: `Remix: ${r.remix_angle}`,
38	    hook: r.hook,
39	    script: r.script,
40	    metadata: {
41	      topic: "Counter-narrative",
42	      hashtags: [],
43	      platforms: ["YOUTUBE", "TIKTOK", "X"] as ("YOUTUBE" | "TIKTOK" | "INSTAGRAM" | "X")[],
44	    },
45	  }));
46	
47	  // D. Low Sentiment Shorts
48	  const lowSentimentItems = (slate.low_sentiment_shorts || []).map((s) => ({
49	    type: "SHORT" as const,
50	    title: `Combat: ${s.topic}`,
51	    hook: s.hook,
52	    script: `${s.hook} ${s.claim} ${s.payoff}`,
53	    metadata: {
54	      topic: s.topic,
55	      hashtags: s.hashtags,
56	      platforms: ["YOUTUBE", "TIKTOK", "INSTAGRAM"] as ("YOUTUBE" | "TIKTOK" | "INSTAGRAM" | "X")[],
57	      is_urgent: false,
58	      is_low_sentiment: true,
59	    },
60	  }));
61	
62	  // 2. Build prioritized queues
63	  const shortsQueue: any[] = [];
64	  const lowSent = [...lowSentimentItems];
65	  const attacks = [
66	    ...shortItems.filter((s) => s.metadata.is_urgent),
67	    ...shortItems.filter((s) => !s.metadata.is_urgent),
68	  ];
69	
70	  // Interleave to spread them out
71	  while (lowSent.length > 0 || attacks.length > 0) {
72	    if (lowSent.length > 0) shortsQueue.push(lowSent.shift()!);
73	    if (attacks.length > 0) shortsQueue.push(attacks.shift()!);
74	  }
75	
76	  const otherQueue = [...remixItems];
77	  const masterQueue = [...shortsQueue, ...otherQueue];
78	
79	  // Find Thursday (0 = Sunday, 1 = Monday, ..., 4 = Thursday)
80	  let thursdayOffset = 0;
81	  for (let i = 0; i < 7; i++) {
82	    const d = new Date(start);
83	    d.setDate(d.getDate() + i);
84	    if (d.getDay() === 4) {
85	      thursdayOffset = i;
86	      break;
87	    }
88	  }
89	
90	  const scheduledDays = new Set<number>();
91	
92	  // A. Lock the Q&A Cluster to Thursday (if exists)
93	  if (slate.qna_clusters && slate.qna_clusters.length > 0) {
94	    const cluster = slate.qna_clusters[0];
95	    const dStart = new Date(start);
96	    dStart.setDate(dStart.getDate() + thursdayOffset);
97	
98	    // 9:00 AM - The Reddit Seed
99	    items.push({
100	      id: `item_cluster_0`,
101	      type: "REDDIT_POST" as const,
102	      title: `CEO Q&A`,
103	      hook: cluster.items.reddit_post.title,
104	      script: cluster.items.reddit_post.body,
105	      metadata: { topic: "Q&A", hashtags: ["AMA"], platforms: ["REDDIT"] as any[], is_urgent: false },
106	      scheduled_at: (() => {
107	        const d = new Date(dStart);
108	        d.setHours(9, 0, 0, 0);
109	        return d.toISOString();
110	      })(),
111	      status: "PLANNED",
112	    });
113	
114	    // 13:00 PM - The Initial React
115	    items.push({
116	      id: `item_cluster_1`,
117	      type: "SHORT" as const,
118	      title: `React: Q&A 1`,
119	      hook: cluster.items.short_react_1.hook,
120	      script: `${cluster.items.short_react_1.hook} ${cluster.items.short_react_1.script}`,
121	      metadata: { topic: "Q&A", hashtags: ["React"], platforms: ["YOUTUBE", "TIKTOK", "INSTAGRAM"] as any[], is_urgent: false },
122	      scheduled_at: (() => {
123	        const d = new Date(dStart);
124	        d.setHours(13, 0, 0, 0);
125	        return d.toISOString();
126	      })(),
127	      status: "PLANNED",
128	    });
129	
130	    // 19:00 PM - The Second React
131	    items.push({
132	      id: `item_cluster_2`,
133	      type: "SHORT" as const,
134	      title: `React: Q&A 2`,
135	      hook: cluster.items.short_react_2.hook,
136	      script: `${cluster.items.short_react_2.hook} ${cluster.items.short_react_2.script}`,
137	      metadata: { topic: "Q&A", hashtags: ["React"], platforms: ["YOUTUBE", "TIKTOK", "INSTAGRAM"] as any[], is_urgent: false },
138	      scheduled_at: (() => {
139	        const d = new Date(dStart);
140	        d.setHours(19, 0, 0, 0);
141	        return d.toISOString();
142	      })(),
143	      status: "PLANNED",
144	    });
145	
146	    scheduledDays.add(thursdayOffset);
147	  }
148	
149	  // B. Distribute remaining days
150	  const availableDays = [0, 1, 2, 3, 4, 5, 6].filter(d => !scheduledDays.has(d));
151	  
152	  const assignedPerDay = new Map<number, any[]>();
153	  for (const d of availableDays) assignedPerDay.set(d, []);
154	
155	  // First pass: 1 item per day to guarantee daily cadence
156	  for (const d of availableDays) {
157	    if (masterQueue.length > 0) {
158	      assignedPerDay.get(d)!.push(masterQueue.shift()!);
159	    }
160	  }
161	
162	  // Second pass: distribute remaining, avoiding same type on same day
163	  while (masterQueue.length > 0) {
164	    const item = masterQueue.shift()!;
165	    let bestDay = availableDays[0];
166	    let bestScore = -1000;
167	
168	    for (const d of availableDays) {
169	      const dayItems = assignedPerDay.get(d)!;
170	      const countScore = -dayItems.length * 10; // prefer days with fewer items
171	      
172	      const hasSameType = dayItems.some(
173	        (i: any) => (i.metadata.is_low_sentiment === (item.metadata as any).is_low_sentiment) && 
174	             (i.metadata.is_competitor_attack === (item.metadata as any).is_competitor_attack)
175	      );
176	      const typeScore = hasSameType ? -5 : 0;
177	      
178	      const dStart = new Date(start);
179	      dStart.setDate(dStart.getDate() + d);
180	      const isWeekend = dStart.getDay() === 0 || dStart.getDay() === 6;
181	      // Heavy penalty for assigning a second item to a weekend
182	      const weekendPenalty = (dayItems.length > 0 && isWeekend) ? -20 : 0;
183	      
184	      const score = countScore + typeScore + weekendPenalty;
185	      if (score > bestScore) {
186	        bestScore = score;
187	        bestDay = d;
188	      }
189	    }
190	    
191	    assignedPerDay.get(bestDay)!.push(item);
192	  }
193	
194	  // Convert map to final schedule
195	  for (const d of availableDays) {
196	    const dayItems = assignedPerDay.get(d)!;
197	    
198	    // Sort so Combat Low Sentiment comes first
199	    dayItems.sort((a, b) => {
200	      const aLow = (a.metadata as any).is_low_sentiment ? 1 : 0;
201	      const bLow = (b.metadata as any).is_low_sentiment ? 1 : 0;
202	      return bLow - aLow; // 1 before 0
203	    });
204	
205	    for (let idx = 0; idx < dayItems.length; idx++) {
206	      const item = dayItems[idx];
207	      const dStart = new Date(start);
208	      dStart.setDate(dStart.getDate() + d);
209	      
210	      const hours = [9, 13, 18];
211	      dStart.setHours(hours[Math.min(idx, 2)], 0, 0, 0);
212	
213	      items.push({
214	        ...item,
215	        id: `item_${d}_${idx}`,
216	        scheduled_at: dStart.toISOString(),
217	        status: "PLANNED",
218	      });
219	    }
220	  }
221	
222	  return {
223	    items,
224	    generated_at: new Date().toISOString(),
225	    brand: slate.brand,
226	  };
227	}
