47	// ── Hook variants ─────────────────────────────────────────────────────────────
48	function buildHookVariants(item: ContentItem): string[] {
49	  const base = item.hook;
50	  return [
51	    base,
52	    `${base}?`,
53	    `Here's why ${item.metadata.topic} changed everything — and most creators missed it.`,
54	    `Unpopular opinion: ${base.charAt(0).toLowerCase() + base.slice(1)}`,
55	    `They never talk about this side of ${item.metadata.topic}. Let's fix that.`,
56	  ];
57	}
58	
59	// ── HookCarousel ─────────────────────────────────────────────────────────────
60	function HookCarousel({ hooks, selectedIdx, onSelect }: { hooks: string[]; selectedIdx: number; onSelect: (idx: number) => void }) {
61	  const prev = useCallback(() => onSelect((selectedIdx - 1 + hooks.length) % hooks.length), [selectedIdx, hooks.length, onSelect]);
62	  const next = useCallback(() => onSelect((selectedIdx + 1) % hooks.length), [selectedIdx, hooks.length, onSelect]);
63	
64	  useEffect(() => {
65	    const onKey = (e: KeyboardEvent) => {
66	      if (e.key === "ArrowLeft") prev();
67	      if (e.key === "ArrowRight") next();
68	    };
69	    window.addEventListener("keydown", onKey);
70	    return () => window.removeEventListener("keydown", onKey);
71	  }, [prev, next]);
72	
73	  return (
74	    <div>
75	      <p className="font-mono text-[10px] uppercase tracking-widest text-neutral-400">
76	        Hook · {selectedIdx + 1}/{hooks.length}
77	      </p>
78	
79	      <div className="mt-3 flex items-start gap-3">
80	        <button
81	          id="hook-prev"
82	          onClick={prev}
83	          aria-label="Previous hook"
84	          className="mt-0.5 text-neutral-300 hover:text-neutral-600 transition-colors"
85	        >
86	          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
87	            <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
88	          </svg>
89	        </button>
90	
91	        <p className="flex-1 text-sm font-medium leading-relaxed text-neutral-700 italic border-l-2 border-accent pl-4">
92	          &ldquo;{hooks[selectedIdx]}&rdquo;
93	        </p>
94	
95	        <button
96	          id="hook-next"
97	          onClick={next}
98	          aria-label="Next hook"
99	          className="mt-0.5 text-neutral-300 hover:text-neutral-600 transition-colors"
100	        >
101	          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
102	            <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
103	          </svg>
104	        </button>
105	      </div>
106	    </div>
107	  );
108	}
109	
110	// ── ContentDetailModal ────────────────────────────────────────────────────────
111	export function ContentDetailModal({ item, onClose }: { item: ContentItem; onClose: () => void }) {
112	  const hooks = buildHookVariants(item);
113	  const [selectedHookIdx, setSelectedHookIdx] = useState(0);
114	  const [images, setImages] = useState<string[]>([]);
115	  const [loadingImages, setLoadingImages] = useState(false);
116	  const [expandedImg, setExpandedImg] = useState<string | null>(null);
117	
118	  const selectedHook = hooks[selectedHookIdx];
119	  const derivedScript = item.script.startsWith(item.hook)
120	    ? item.script.replace(item.hook, selectedHook)
121	    : `${selectedHook}\n\n${item.script}`;
122	
123	  useEffect(() => {
124	    async function fetchImages() {
125	      setLoadingImages(true);
126	      try {
127	        const res = await fetch(`/api/images?topic=${encodeURIComponent(item.metadata.topic)}`);
128	        if (res.ok) {
129	          const data = await res.json();
130	          setImages(data.images || []);
131	        }
132	      } catch (err) {
133	        console.error("Failed to fetch images", err);
134	      } finally {
135	        setLoadingImages(false);
136	      }
137	    }
138	    fetchImages();
139	  }, [item.metadata.topic]);
140	
141	  useEffect(() => {
142	    const onKey = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
143	    window.addEventListener("keydown", onKey);
144	    return () => window.removeEventListener("keydown", onKey);
145	  }, [onClose]);
146	
147	  const typeLabel: Record<ContentItem["type"], string> = {
148	    SHORT: "Short",
149	    PITCH_PROMO: "Pitch",
150	    REMIX: "Remix",
151	    REDDIT_POST: "Reddit AMA",
152	  };
153	
154	  const scheduled = new Date(item.scheduled_at);
155	
156	  return (
157	    <div
158	      id="content-detail-backdrop"
159	      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center"
160	      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
161	    >
162	      {/* Overlay */}
163	      <div className="absolute inset-0 bg-ink/30" onClick={onClose} />
164	
165	      {/* Panel — matches the existing card/section style */}
166	      <article
167	        id="content-detail-panel"
168	        className="relative z-10 w-full sm:max-w-xl max-h-[85vh] overflow-y-auto bg-white rounded-t-3xl sm:rounded-2xl border border-neutral-200 shadow-xl"
169	      >
170	        {/* Top bar */}
171	        <div className="flex items-center justify-between px-7 pt-6 pb-4 border-b border-neutral-100">
172	          <div className="flex items-center gap-3">
173	            <span className="font-mono text-[10px] uppercase tracking-widest text-neutral-400">
174	              {typeLabel[item.type]}
175	            </span>
176	            <span className="text-neutral-200">·</span>
177	            <span className="font-mono text-[10px] uppercase tracking-widest text-neutral-400">
178	              {scheduled.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" })}{" "}
179	              {scheduled.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit", hour12: true })}
180	            </span>
181	          </div>
182	          <button
183	            id="content-detail-close"
184	            onClick={onClose}
185	            aria-label="Close"
186	            className="text-neutral-300 hover:text-neutral-600 transition-colors"
187	          >
188	            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
189	              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
190	            </svg>
191	          </button>
192	        </div>
193	
194	        <div className="px-7 py-6 space-y-7">
195	          {/* Title */}
196	          <div>
197	            <h2 className="text-xl font-semibold leading-snug text-ink">{item.title}</h2>
198	            <div className="mt-2 flex flex-wrap gap-2">
199	              {item.metadata.is_low_sentiment && (
200	                <span className="text-[8px] font-semibold uppercase tracking-wider text-red-500 flex items-center gap-1 bg-red-50 px-2 py-1 rounded-md">
201	                  <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
202	                    <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
203	                  </svg>
204	                  Combat Low Sentiment
205	                </span>
206	              )}
207	              {item.metadata.is_competitor_attack && !item.metadata.is_low_sentiment && (
208	                <span className="text-[8px] font-semibold uppercase tracking-wider text-amber-500 flex items-center gap-1 bg-amber-50 px-2 py-1 rounded-md">
209	                  <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
210	                    <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
211	                  </svg>
212	                  Competitor Attack
213	                </span>
214	              )}
215	            </div>
216	          </div>
217	
218	          {/* Hook carousel */}
219	          <HookCarousel hooks={hooks} selectedIdx={selectedHookIdx} onSelect={setSelectedHookIdx} />
220	
221	          {/* Script */}
222	          <div>
223	            <p className="font-mono text-[10px] uppercase tracking-widest text-neutral-400 mb-3">Script</p>
224	            <p className="text-sm leading-relaxed text-neutral-700 whitespace-pre-wrap">{derivedScript}</p>
225	          </div>
226	
227	          {/* Platforms */}
228	          <div className="flex items-center gap-2">
229	            {item.metadata.platforms.map((p) => (
230	              <PlatformIcon key={p} platform={p} />
231	            ))}
232	          </div>
233	
234	          {/* Hashtags */}
235	          {item.metadata.hashtags.length > 0 && (
236	            <div className="flex flex-wrap gap-x-3 gap-y-1">
237	              {item.metadata.hashtags.map((h) => (
238	                <span key={h} className="text-xs text-accent">{h}</span>
239	              ))}
240	            </div>
241	          )}
242	
243	          {/* B-Roll Images */}
244	          <div>
245	            <p className="font-mono text-[10px] uppercase tracking-widest text-neutral-400 mb-3">B-Roll Images</p>
246	            {loadingImages ? (
247	              <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
248	                {[1, 2, 3].map(i => (
249	                  <div key={i} className="w-24 aspect-[9/16] shrink-0 bg-neutral-100 rounded-lg animate-pulse" />
250	                ))}
251	              </div>
252	            ) : images.length > 0 ? (
253	              <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
254	                {images.map((img, i) => (
255	                  <div 
256	                    key={i} 
257	                    className="relative group shrink-0 w-24 aspect-[9/16] rounded-lg overflow-hidden border border-neutral-200 cursor-zoom-in"
258	                    onClick={() => setExpandedImg(img)}
259	                  >
260	                    <img src={img} alt="B-roll" className="w-full h-full object-cover" />
261	                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
262	                      <a 
263	                        href={img} 
264	                        download 
265	                        target="_blank" 
266	                        rel="noreferrer"
267	                        onClick={(e) => e.stopPropagation()}
268	                        className="p-1.5 bg-white/20 hover:bg-white/40 rounded-md backdrop-blur-sm transition-colors"
269	                        title="Download image"
270	                      >
271	                        <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
272	                          <path strokeLinecap="round" strokeLinejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
273	                        </svg>
274	                      </a>
275	                    </div>
276	                  </div>
277	                ))}
278	              </div>
279	            ) : (
280	              <p className="text-xs text-neutral-400 italic">No images found for this topic.</p>
281	            )}
282	          </div>
283	
284	          {/* Actions */}
285	          <div className="flex items-center gap-3 pt-1 pb-1">
286	            <Link
287	              href={`/teleprompter?script=${encodeURIComponent(derivedScript)}`}
288	              id="content-detail-record"
289	              className="inline-flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-ink border border-neutral-200 px-4 py-2.5 rounded-full hover:border-ink transition-colors"
290	            >
291	              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
292	                <path strokeLinecap="round" strokeLinejoin="round" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
293	              </svg>
294	              Record Take
295	            </Link>
296	            <button
297	              id="content-detail-copy"
298	              onClick={() => navigator.clipboard.writeText(derivedScript)}
299	              className="font-mono text-[10px] uppercase tracking-widest text-neutral-400 hover:text-neutral-700 transition-colors"
300	            >
301	              Copy Script
302	            </button>
303	          </div>
304	        </div>
305	      </article>
306	
307	      {/* Expanded Image Lightbox */}
308	      {expandedImg && (
309	        <div 
310	          className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 cursor-zoom-out"
311	          onClick={() => setExpandedImg(null)}
312	        >
313	          <div className="relative max-w-full max-h-full">
314	            <img 
315	              src={expandedImg} 
316	              alt="Expanded B-roll" 
317	              className="max-w-full max-h-[90vh] object-contain rounded-lg shadow-2xl" 
318	            />
319	            <a 
320	              href={expandedImg} 
321	              download 
322	              target="_blank" 
323	              rel="noreferrer"
324	              onClick={(e) => e.stopPropagation()}
325	              className="absolute top-4 right-4 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white backdrop-blur-md transition-colors"
326	              title="Download image"
327	            >
328	              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
329	                <path strokeLinecap="round" strokeLinejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
330	              </svg>
331	            </a>
332	          </div>
333	        </div>
334	      )}
335	    </div>
336	  );
337	}
338	
339	// ── ContentCard ───────────────────────────────────────────────────────────────
340	export function ContentCard({ item }: { item: ContentItem }) {
341	  const [open, setOpen] = useState(false);
342	  const [done, setDone] = useState(false);
343	
344	  // Persist done state per item across page refreshes
345	  useEffect(() => {
346	    const stored = localStorage.getItem(`done:${item.id}`);
347	    if (stored === "1") setDone(true);
348	  }, [item.id]);
349	
350	  const toggleDone = (e: React.MouseEvent) => {
351	    e.stopPropagation();
352	    const next = !done;
353	    setDone(next);
354	    localStorage.setItem(`done:${item.id}`, next ? "1" : "0");
355	  };
356	
357	  const typeColors: Record<ContentItem["type"], string> = {
358	    SHORT: "bg-indigo-50 text-indigo-600",
359	    PITCH_PROMO: "bg-neutral-50 text-neutral-400",
360	    REMIX: "bg-fuchsia-50 text-fuchsia-600",
361	    REDDIT_POST: "bg-orange-50 text-orange-600",
362	  };
363	
364	  return (
365	    <>
366	      <article
367	        id={`content-card-${item.id}`}
368	        className={`group relative rounded-2xl border px-4 py-3.5 bg-white transition-all flex flex-col h-40 ${
369	          done
370	            ? "border-neutral-100 opacity-50"
371	            : "border-neutral-200 hover:border-accent hover:shadow-[0_10px_30px_-10px_rgba(99,102,241,0.2)]"
372	        }`}
373	      >
374	        <div className="flex justify-between items-start">
375	          <span className={`text-[8px] font-mono font-bold uppercase tracking-widest px-2 py-1 rounded-md ${typeColors[item.type]}`}>
376	            {item.type.replace(/_/g, " ")}
377	          </span>
378	
379	          {/* Done checkmark */}
380	          <button
381	            id={`content-card-done-${item.id}`}
382	            onClick={toggleDone}
383	            aria-label={done ? "Mark as not done" : "Mark as done"}
384	            className={`w-4 h-4 rounded-full border flex items-center justify-center transition-colors flex-shrink-0 ${
385	              done
386	                ? "border-emerald-400 bg-emerald-400"
387	                : "border-neutral-300 hover:border-neutral-500"
388	            }`}
389	          >
390	            {done && (
391	              <svg className="w-2.5 h-2.5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
392	                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
393	              </svg>
394	            )}
395	          </button>
396	        </div>
397	
398	        {/* Clickable title */}
399	        <button
400	          id={`content-card-title-${item.id}`}
401	          onClick={() => setOpen(true)}
402	          className={`mt-2 text-left text-xs font-semibold leading-snug transition-colors line-clamp-2 hover:underline underline-offset-2 ${
403	            done ? "line-through text-neutral-400" : "text-ink group-hover:text-accent"
404	          }`}
405	        >
406	          {item.title}
407	        </button>
408	
409	        <div className="mt-1.5 flex items-center gap-1.5">
410	          {item.metadata.platforms.map((p) => (
411	            <PlatformIcon key={p} platform={p} />
412	          ))}
413	        </div>
414	
415	        {item.metadata.is_low_sentiment && (
416	          <div className="mt-1.5">
417	            <span className="text-[8px] font-semibold uppercase tracking-wider text-red-500 flex items-center gap-1">
418	              <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
419	                <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
420	              </svg>
421	              Combat Low Sentiment
422	            </span>
423	          </div>
424	        )}
425	
426	        {item.metadata.is_competitor_attack && !item.metadata.is_low_sentiment && (
427	          <div className="mt-1.5">
428	            <span className="text-[8px] font-semibold uppercase tracking-wider text-amber-500 flex items-center gap-1">
429	              <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
430	                <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
431	              </svg>
432	              Competitor Attack
433	            </span>
434	          </div>
435	        )}
436	
437	        {!done && (
438	          <div className="mt-auto pt-2 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-all transform translate-y-1 group-hover:translate-y-0">
439	            <Link
440	              href={`/teleprompter?script=${encodeURIComponent(item.script)}`}
441	              className="inline-flex items-center gap-1 text-[10px] font-bold text-accent uppercase tracking-wider"
442	            >
443	              Record Take
444	              <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
445	                <path strokeLinecap="round" strokeLinejoin="round" d="M14 5l7 7-7 7" />
446	              </svg>
447	            </Link>
448	          </div>
449	        )}
450	      </article>
451	
452	      {open && <ContentDetailModal item={item} onClose={() => setOpen(false)} />}
453	    </>
454	  );
455	}
