// ── ContentCard ───────────────────────────────────────────────────────────────
export function ContentCard({ item }: { item: ContentItem }) {
  const [open, setOpen] = useState(false);
  const [done, setDone] = useState(false);

  // Persist done state per item across page refreshes
  useEffect(() => {
    const stored = localStorage.getItem(`done:${item.id}`);
    if (stored === "1") setDone(true);
  }, [item.id]);

  const toggleDone = (e: React.MouseEvent) => {
    e.stopPropagation();
    const next = !done;
    setDone(next);
    localStorage.setItem(`done:${item.id}`, next ? "1" : "0");
  };

  const typeColors: Record<ContentItem["type"], string> = {
    SHORT: "bg-indigo-50 text-indigo-600",
    PITCH_PROMO: "bg-neutral-50 text-neutral-400",
    REMIX: "bg-fuchsia-50 text-fuchsia-600",
    REDDIT_POST: "bg-orange-50 text-orange-600",
  };

  return (
    <>
      <article
        id={`content-card-${item.id}`}
        className={`group relative rounded-2xl border px-4 py-3.5 bg-white transition-all flex flex-col h-40 ${
          done
            ? "border-neutral-100 opacity-50"
            : "border-neutral-200 hover:border-accent hover:shadow-[0_10px_30px_-10px_rgba(99,102,241,0.2)]"
        }`}
      >
        <div className="flex justify-between items-start">
          <span className={`text-[8px] font-mono font-bold uppercase tracking-widest px-2 py-1 rounded-md ${typeColors[item.type]}`}>
            {item.type.replace(/_/g, " ")}
          </span>

          {/* Done checkmark */}
          <button
            id={`content-card-done-${item.id}`}
            onClick={toggleDone}
            aria-label={done ? "Mark as not done" : "Mark as done"}
            className={`w-4 h-4 rounded-full border flex items-center justify-center transition-colors flex-shrink-0 ${
              done
                ? "border-emerald-400 bg-emerald-400"
                : "border-neutral-300 hover:border-neutral-500"
            }`}
          >
            {done && (
              <svg className="w-2.5 h-2.5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
              </svg>
            )}
          </button>
        </div>

        {/* Clickable title */}
        <button
          id={`content-card-title-${item.id}`}
          onClick={() => setOpen(true)}
          className={`mt-2 text-left text-xs font-semibold leading-snug transition-colors line-clamp-2 hover:underline underline-offset-2 ${
            done ? "line-through text-neutral-400" : "text-ink group-hover:text-accent"
          }`}
        >
          {item.title}
        </button>

        <div className="mt-1.5 flex items-center gap-1.5">
          {item.metadata.platforms.map((p) => (
            <PlatformIcon key={p} platform={p} />
          ))}
        </div>

        {item.metadata.is_low_sentiment && (
          <div className="mt-1.5">
            <span className="text-[8px] font-semibold uppercase tracking-wider text-red-500 flex items-center gap-1">
              <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              Combat Low Sentiment
            </span>
          </div>
        )}

        {item.metadata.is_competitor_attack && !item.metadata.is_low_sentiment && (
          <div className="mt-1.5">
            <span className="text-[8px] font-semibold uppercase tracking-wider text-amber-500 flex items-center gap-1">
              <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
              Competitor Attack
            </span>
          </div>
        )}

        {!done && (
          <div className="mt-auto pt-2 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-all transform translate-y-1 group-hover:translate-y-0">
            <Link
              href={`/teleprompter?script=${encodeURIComponent(item.script)}`}
              className="inline-flex items-center gap-1 text-[10px] font-bold text-accent uppercase tracking-wider"
            >
              Record Take
              <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M14 5l7 7-7 7" />
              </svg>
            </Link>
          </div>
        )}
      </article>

      {open && <ContentDetailModal item={item} onClose={() => setOpen(false)} />}
    </>
  );
}

import type { SourceGap } from "@/lib/pipeline/types";

const CLASSIFICATION_COLOR: Record<string, { bg: string; text: string }> = {
  UGC:          { bg: "bg-violet-50",  text: "text-violet-600"  },
  EDITORIAL:    { bg: "bg-blue-50",    text: "text-blue-600"    },
  CORPORATE:    { bg: "bg-amber-50",   text: "text-amber-600"   },
  REFERENCE:    { bg: "bg-emerald-50", text: "text-emerald-600" },
  INSTITUTIONAL:{ bg: "bg-rose-50",   text: "text-rose-600"    },
  OTHER:        { bg: "bg-neutral-50", text: "text-neutral-500" },
};

function classColors(c: string) {
  return CLASSIFICATION_COLOR[(c ?? "").toUpperCase()] ?? CLASSIFICATION_COLOR["OTHER"];
}

function UrgencyBar({ score, max }: { score: number; max: number }) {
  const pct = max > 0 ? Math.round((score / max) * 100) : 0;
  const color = pct > 66 ? "bg-red-500" : pct > 33 ? "bg-amber-400" : "bg-emerald-400";
  return (
    <div className="flex items-center gap-2">
      <div className="flex-1 h-1 rounded-full bg-neutral-100 overflow-hidden">
        <div className={`h-full rounded-full ${color} transition-all`} style={{ width: `${pct}%` }} />
      </div>
      <span className="font-mono text-[9px] text-neutral-400 w-8 text-right">{pct}%</span>
    </div>
  );
}

