import { NextRequest, NextResponse } from "next/server";
import { writeFile, mkdir } from "node:fs/promises";
import { join } from "node:path";
import { generateSlate } from "@/lib/pipeline/slate";
import { resolveProject } from "@/lib/peec/projects";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";
export const maxDuration = 120;

export async function POST(req: NextRequest) {
  if (!process.env.GEMINI_API_KEY) {
    return NextResponse.json({ error: "GEMINI_API_KEY not configured in .env" }, { status: 500 });
  }
  try {
    const body = (await req.json().catch(() => ({}))) as { project?: string };
    const target = await resolveProject(body.project);
    const slate = await generateSlate(target.id);

    const dir = "data/slate";
    await mkdir(dir, { recursive: true });
    const stamp = new Date().toISOString().replace(/[:.]/g, "-");
    const slug = target.name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
    await writeFile(join(dir, `${slug}-${stamp}.json`), JSON.stringify(slate, null, 2));
    await writeFile(join(dir, "latest.json"), JSON.stringify(slate, null, 2));

    return NextResponse.json({ ok: true, brand: slate.brand.name, project: target });
  } catch (e) {
    return NextResponse.json({ error: (e as Error).message }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { tavilySearch, hasTavily } from "@/lib/tavily/client";

export async function GET(request: Request) {
  if (!hasTavily) {
    return NextResponse.json({ images: [] });
  }

  const { searchParams } = new URL(request.url);
  const topic = searchParams.get("topic");

  if (!topic) {
    return NextResponse.json({ error: "Missing topic parameter" }, { status: 400 });
  }

  try {
    const data = await tavilySearch({
      query: `high quality vertical portrait background images for ${topic} 9:16`,
      include_images: true,
      max_results: 3,
    });

    return NextResponse.json({ images: data.images || [] });
  } catch (error) {
    console.error("Image search failed:", error);
    return NextResponse.json({ error: "Failed to fetch images" }, { status: 500 });
  }
}

import { peec } from "../peec/client";
import { generateJSON } from "../llm/client";
import type { RemixScript } from "./types";
import type { UrlReportRow, Brand } from "../peec/types";

type Args = {
  projectId: string;
  ownBrand: Brand;
  allBrands: Brand[];
  urlReport: UrlReportRow[];
};

export async function buildRemixes(args: Args): Promise<RemixScript[]> {
  const { projectId, ownBrand, allBrands, urlReport } = args;

  const ownId = ownBrand.id;
  const gapUrls = urlReport.filter(u => {
    const mentioned = u.mentioned_brands.map(b => b.id);
    if (mentioned.includes(ownId)) return false;
    const hasCompetitor = mentioned.some(id => allBrands.some(b => !b.is_own && b.id === id));
    return hasCompetitor && u.retrievals > 0;
  }).sort((a, b) => b.retrievals - a.retrievals);

  if (gapUrls.length === 0) return [];

  const targetUrl = gapUrls[0];
  const compBrands = targetUrl.mentioned_brands
    .map(b => allBrands.find(a => a.id === b.id)?.name)
    .filter(Boolean) as string[];

  let sourceContent = "";
  try {
    const contentRes = await peec.urlContent(projectId, { url: targetUrl.url, max_length: 5000 });
    sourceContent = contentRes.content;
  } catch (e) {
    console.warn(`[remixes] Failed to fetch urlContent for ${targetUrl.url}: ${e}`);
    return [];
  }

  if (!sourceContent || sourceContent.length < 100) return [];

  return generateJSON<RemixScript[]>({
    system: remixSystem(ownBrand.name),
    user: JSON.stringify({
      brand: ownBrand.name,
      competitors_mentioned: compBrands,
      source_url: targetUrl.url,
      source_title: targetUrl.title,
      source_content: sourceContent
    }, null, 2)
  });
}

