import type { DomainReportRow, Brand } from "../peec/types";
import type { SourceGap, GapAnalysis } from "./types";
import { generateJSON } from "../llm/client";

const ACTION_MAP: Record<string, { action: string; format: string }> = {
  UGC: { action: "Community post or creator collab", format: "Reddit thread, YouTube Shorts, TikTok" },
  EDITORIAL: { action: "PR / journalist pitch", format: "Press release, product loan, exclusive briefing" },
  CORPORATE: { action: "Partnership or directory listing", format: "Guest post, directory submission, co-marketing" },
  REFERENCE: { action: "Content correction or addition", format: "Wikipedia edit, spec-site submission, data update" },
  INSTITUTIONAL: { action: "Academic or institutional outreach", format: "White paper, research collaboration, case study" },
  OTHER: { action: "Content presence", format: "SEO-optimised page, brand mention outreach" },
};

export async function computeGapAnalysis(domainReport: DomainReportRow[], ownBrand: Brand, allBrands: Brand[]): Promise<GapAnalysis> {
  const ownId = ownBrand.id;
  const gaps: SourceGap[] = [];
  for (const domain of domainReport) {
    if (domain.classification === "You") continue;
    const mentionedIds = domain.mentioned_brands.map((b) => b.id);
    if (mentionedIds.includes(ownId)) continue;
    const competitorBrands = allBrands.filter((b) => !b.is_own && mentionedIds.includes(b.id));
    if (competitorBrands.length === 0) continue;
    const gapScore = Number((domain.retrieved_percentage * domain.citation_rate * competitorBrands.length).toFixed(3));
    const classification = (domain.classification ?? "OTHER").toUpperCase();
    const mapped = ACTION_MAP[classification] ?? ACTION_MAP["OTHER"];
    gaps.push({
      domain: domain.domain,
      classification: domain.classification ?? "Other",
      retrieved_percentage: Number((domain.retrieved_percentage * 100).toFixed(1)),
      retrieval_rate: Number(domain.retrieval_rate.toFixed(3)),
      citation_rate: Number(domain.citation_rate.toFixed(2)),
      competitors_present: competitorBrands.map((b) => b.name),
      gap_score: gapScore,
      recommended_action: mapped.action,
      content_format: mapped.format,
    });
  }
  gaps.sort((a, b) => b.gap_score - a.gap_score);
  const candidates = gaps.slice(0, 15);
  if (candidates.length === 0) return { gaps: [], total_gaps_found: 0, summary: `${ownBrand.name} appears on all major AI-cited domains.` };
  const systemPrompt = `You are a strict outreach strategist for the brand "${ownBrand.name}". Reject competitor-owned domains. Return JSON array of approved domain strings.`;
  let approvedDomains: string[] = [];
  try {
    approvedDomains = await generateJSON<string[]>({ system: systemPrompt, user: JSON.stringify(candidates.map(c => c.domain)), temperature: 0.1 });
  } catch (error) {
    approvedDomains = candidates.map(c => c.domain);
  }
  const validSet = new Set(approvedDomains);
  const filteredGaps = candidates.filter(g => validSet.has(g.domain));
  return { gaps: filteredGaps.slice(0, 5), total_gaps_found: filteredGaps.length, summary: "" };
}

