let _cache = null;
const TTL_MS = 60000;
export async function listProjects() {
  if (_cache && Date.now() - _cache.at < TTL_MS) return _cache.projects;
  const projects = await peec.listProjects();
  _cache = { at: Date.now(), projects };
  return projects;
}
export async function resolveProject(input) {
  const projects = await listProjects();
  if (!input) return projects[0];
  if (input.startsWith("or_")) {
    const exact = projects.find(p => p.id === input);
    if (exact) return exact;
    return { id: input, name: input, status: "UNKNOWN" };
  }
  const normalised = input.toLowerCase().trim();
  const match = projects.find(p => p.name.toLowerCase() === normalised) ?? projects.find(p => p.name.toLowerCase().includes(normalised));
  if (match) return match;
  throw new Error(`No project matched "${input}"`);
}

