export async function buildPitches(args) {
  const urls = await peec.urlReport(args.projectId, { ...args.range, limit: 200 });
  const yt = urls.filter(u => u.url.includes("youtube.com") && u.channel_title);
  const byChannel = new Map();
  for (const u of yt) {
    const key = u.channel_title;
    const channelUrl = `https://youtube.com/@${key.replace(/\s+/g, "")}`;
    const cur = byChannel.get(key) ?? { channel_title: key, channel_url: channelUrl, total_retrievals: 0, total_citations: 0, videos: [] };
    cur.total_retrievals += u.retrievals;
    cur.total_citations += u.citation_count;
    cur.videos.push({ url: u.url, title: u.title });
    byChannel.set(key, cur);
  }
  const ranked = [...byChannel.values()].sort((a, b) => b.total_retrievals + b.total_citations - (a.total_retrievals + a.total_citations)).slice(0, 5);
  if (ranked.length === 0) return [];
  return generateJSON({ system: `You are an outreach strategist for ${args.ownBrandName}.`, user: JSON.stringify({ candidates: ranked }) });
}

