    if (mentioned.includes(ownId)) return false;
    const hasCompetitor = mentioned.some(id => args.allBrands.some(b => !b.is_own && b.id === id));
    return hasCompetitor && u.retrievals > 0;
  }).sort((a, b) => b.retrievals - a.retrievals);
  if (gapUrls.length === 0) return [];
  const targetUrl = gapUrls[0];
  let sourceContent = "";
  try {
    const contentRes = await peec.urlContent(args.projectId, { url: targetUrl.url, max_length: 5000 });
    sourceContent = contentRes.content;
  } catch (e) { return []; }
  if (!sourceContent || sourceContent.length < 100) return [];
  return generateJSON({ system: `You are a growth marketer for ${args.ownBrand.name}.`, user: JSON.stringify({ source_content: sourceContent }) });
}

